// Replace placeholders with your Tollara listing + subscriber service key
return [{
  json: {
    serviceKey: 'YOUR_SERVICE_KEY',
    serviceId: 'YOUR_SERVICE_ID',
    endpointId: 'YOUR_URL_METADATA_ENDPOINT_ID',
    invokeBody: JSON.stringify({ url: 'https://example.com' }),
  },
}];

const invoke = $('Tollara Invoke').first().json;
const data = invoke.data ?? {};
return [{
  json: {
    statusCode: invoke.statusCode,
    url: data.url,
    title: data.title,
    description: data.description,
    raw: invoke.body,
  },
}];
